
'use client';

import { useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { toast } from 'sonner';
import { getUsersAction, addUserAction, getSettingsAction } from '@/app/actions/dbActions';
import { Loader2, ArrowRight } from 'lucide-react';
import Image from 'next/image';

interface SignupPageProps {
  onSwitchToLogin: () => void;
}

export default function SignupPage({ onSwitchToLogin }: SignupPageProps) {
  const [formData, setFormData] = useState({
    id: '',
    name: '',
    email: '',
    password: '',
    confirmPassword: '',
    role: 'student' as 'teacher' | 'student',
    program: '',
    year: 1,
    teacherSecret: '',
  });
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    if (formData.password !== formData.confirmPassword) {
      toast.error('Passwords do not match');
      setLoading(false);
      return;
    }

    try {
        if (formData.role === 'teacher') {
            const settings = await getSettingsAction();
            if (formData.teacherSecret !== settings.teacherSecret) {
                toast.error('Invalid teacher secret code.');
                setLoading(false);
                return;
            }
        }

      const users = await getUsersAction();
      if (users.find(u => u.id === formData.id)) {
        toast.error('USN/EMP number already exists');
        setLoading(false);
        return;
      }

      const newUser = {
        id: formData.id,
        name: formData.name,
        email: formData.email,
        password: formData.password,
        role: formData.role,
        ...(formData.role === 'student' && {
          program: formData.program,
          year: formData.year
        }),
        profilePic: ''
      };

      await addUserAction(newUser);
      login(newUser);
      localStorage.setItem('currentUserId', newUser.id);
      toast.success('Account created successfully!');
    } catch (error) {
      console.error(error);
      toast.error('Failed to create account');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-muted/30 flex flex-col">
       <header className="bg-primary shadow-md">
        <div className="container mx-auto px-6 py-4">
          <Image src="/logo.png" alt="AMA Student Portal" width={150} height={40} />
        </div>
      </header>

      <main className="flex-grow flex items-center justify-center p-4">
        <div className="w-full max-w-4xl bg-white rounded-2xl shadow-2xl overflow-hidden flex flex-col md:flex-row">
            <div className="w-full md:w-2/5 bg-primary text-white p-12 flex flex-col justify-center items-start">
                <h1 className="text-4xl font-bold mb-4">Create Account</h1>
                <p className="text-white/80 leading-relaxed">
                Join our digital campus. A seamless experience for students and faculty awaits.
                </p>
            </div>

            <div className="w-full md:w-3/5 p-12 overflow-y-auto">
                <h2 className="text-2xl font-bold mb-2">Registration</h2>
                <p className="text-muted-foreground mb-8">Get started with your new account.</p>
                <form onSubmit={handleSubmit} className="space-y-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label htmlFor="id">USN / EMP Number</Label>
                            <Input
                            id="id"
                            placeholder="ID Number"
                            value={formData.id}
                            onChange={(e) => setFormData({ ...formData, id: e.target.value })}
                            required
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="name">Full Name</Label>
                            <Input
                            id="name"
                            placeholder="John Doe"
                            value={formData.name}
                            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                            required
                            />
                        </div>
                    </div>
                    
                    <div className="space-y-2">
                    <Label htmlFor="email">Email Address</Label>
                    <Input
                        id="email"
                        type="email"
                        placeholder="name@school.edu"
                        value={formData.email}
                        onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                        required
                    />
                    </div>

                    <div className="space-y-2">
                    <Label htmlFor="role">Your Role</Label>
                    <Select
                        value={formData.role}
                        onValueChange={(value: 'teacher' | 'student') => setFormData({ ...formData, role: value })}
                    >
                        <SelectTrigger className="h-12">
                        <SelectValue placeholder="Select role" />
                        </SelectTrigger>
                        <SelectContent>
                        <SelectItem value="student">Student</SelectItem>
                        <SelectItem value="teacher">Teacher</SelectItem>
                        </SelectContent>
                    </Select>
                    </div>

                    {formData.role === 'teacher' && (
                        <div className="space-y-2">
                            <Label htmlFor="teacherSecret">Teacher Secret Code</Label>
                            <Input
                                id="teacherSecret"
                                type="password"
                                placeholder="Enter secret code"
                                value={formData.teacherSecret}
                                onChange={(e) => setFormData({ ...formData, teacherSecret: e.target.value })}
                                required
                            />
                        </div>
                    )}


                    {formData.role === 'student' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-2">
                        <div className="space-y-2">
                        <Label htmlFor="program">Program</Label>
                        <Input
                            id="program"
                            placeholder="e.g., BSCS"
                            value={formData.program}
                            onChange={(e) => setFormData({ ...formData, program: e.target.value })}
                            required
                        />
                        </div>
                        <div className="space-y-2">
                        <Label htmlFor="year">Year Level</Label>
                        <Select
                            value={formData.year.toString()}
                            onValueChange={(value) => setFormData({ ...formData, year: parseInt(value) })}
                        >
                            <SelectTrigger>
                            <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                            <SelectItem value="1">1st Year</SelectItem>
                            <SelectItem value="2">2nd Year</SelectItem>
                            <SelectItem value="3">3rd Year</SelectItem>
                            <SelectItem value="4">4th Year</SelectItem>
                            </SelectContent>
                        </Select>
                        </div>
                    </div>
                    )}

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-2">
                        <Label htmlFor="password">Password</Label>
                        <Input
                        id="password"
                        type="password"
                        value={formData.password}
                        onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                        required
                        />
                    </div>
                    <div className="space-y-2">
                        <Label htmlFor="confirmPassword">Confirm Password</Label>
                        <Input
                        id="confirmPassword"
                        type="password"
                        value={formData.confirmPassword}
                        onChange={(e) => setFormData({ ...formData, confirmPassword: e.target.value })}
                        required
                        />
                    </div>
                    </div>

                    <Button 
                    type="submit" 
                    className="w-full h-12 text-lg font-bold bg-primary hover:bg-primary/90 mt-4 shadow-lg rounded-lg" 
                    disabled={loading}
                    >
                    {loading ? <Loader2 className="h-5 w-5 animate-spin" /> : 'Create Account'}
                    </Button>
                    <div className="text-center text-sm pt-2">
                    <span className="text-muted-foreground">Already have an account? </span>
                    <button
                        type="button"
                        onClick={onSwitchToLogin}
                        className="font-semibold text-primary hover:underline"
                    >
                        Sign in
                    </button>
                    </div>
                </form>
            </div>
        </div>
      </main>
    </div>
  );
}
