
'use client';

import { useState, useEffect } from 'react';
import Image from 'next/image';
import { useAuth } from '@/contexts/AuthContext';
import { getUsersAction, getEnrollmentsAction, getLabRequestsAction, getSubjectsAction } from '@/app/actions/dbActions';
import { Card, CardContent } from '@/components/ui/card';
import {
  Users,
  BookOpen,
  GraduationCap,
  Monitor,
  Calendar,
} from 'lucide-react';
import AdminSidebar from './AdminSidebar';

const StatCard = ({ icon: Icon, title, value, color, bgColor }) => (
  <Card className="shadow hover:shadow-md transition-shadow rounded-xl">
    <CardContent className="pt-6 flex items-center gap-4">
      <div className={`p-3 rounded-lg ${bgColor}`}>
        <Icon className={`w-6 h-6 ${color}`} />
      </div>
      <div>
        <p className="text-gray-500 font-medium">{title}</p>
        <p className="text-3xl font-bold text-gray-900">{value}</p>
      </div>
    </CardContent>
  </Card>
);

export default function AdminDashboard() {
  const [totalUsers, setTotalUsers] = useState(0);
  const [teacherCount, setTeacherCount] = useState(0);
  const [studentCount, setStudentCount] = useState(0);
  const [enrollmentCount, setEnrollmentCount] = useState(0);
  const [activeSessions, setActiveSessions] = useState(0);
  const [sessionsToday, setSessionsToday] = useState(0);

  useEffect(() => {
    async function fetchData() {
      try {
        const [users, enrollments, requests] = await Promise.all([
            getUsersAction(),
            getEnrollmentsAction(),
            getLabRequestsAction()
        ]);
        
        setTotalUsers(users.length);
        setTeacherCount(users.filter(u => u.role === 'teacher').length);
        setStudentCount(users.filter(u => u.role === 'student').length);
        setEnrollmentCount(enrollments.length);

        const now = new Date();
        const todayStr = now.toISOString().split('T')[0];
        
        const todayRequests = requests.filter(r => r.startTime.startsWith(todayStr));
        setSessionsToday(todayRequests.length);

        const currentActive = requests.filter(r => {
            const startTime = new Date(r.startTime);
            const endTime = new Date(r.endTime);
            return r.status === 'approved' && now >= startTime && now <= endTime;
        });
        setActiveSessions(currentActive.length);

      } catch (e) {
        console.error("Failed to fetch dashboard data:", e);
      }
    }
    fetchData();
  }, []);
  
  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      <header className="bg-primary shadow-lg sticky top-0 z-20">
        <div className="mx-auto px-8 h-16 flex items-center">
          <Image src="/logo.png" alt="AMA Student Portal" width={150} height={38} priority />
        </div>
      </header>
      <div className="flex flex-1">
        <AdminSidebar />
        <main className="flex-1 p-8 overflow-y-auto">
          <div className="mb-8">
            <h1 className="text-3xl font-bold text-gray-800">Admin Dashboard</h1>
            <p className="text-gray-500">System overview and statistics</p>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
            <StatCard icon={Users} title="Total Users" value={totalUsers} color="text-red-500" bgColor="bg-red-50" />
            <StatCard icon={GraduationCap} title="Teachers" value={teacherCount} color="text-blue-500" bgColor="bg-blue-50" />
            <StatCard icon={Users} title="Students" value={studentCount} color="text-green-500" bgColor="bg-green-50" />
            <StatCard icon={BookOpen} title="Enrollments" value={enrollmentCount} color="text-purple-500" bgColor="bg-purple-50" />
            <StatCard icon={Monitor} title="Active Sessions" value={activeSessions} color="text-sky-500" bgColor="bg-sky-50" />
            <StatCard icon={Calendar} title="Sessions Today" value={sessionsToday} color="text-orange-500" bgColor="bg-orange-50" />
          </div>
        </main>
      </div>
    </div>
  );
}
